const crypto = require('crypto');
const payload = JSON.stringify($input.first().json.body);
const secret = $env.WHATSAPP_APP_SECRET;
const signature = $input.first().headers['x-hub-signature-256'];
const expected = 'sha256=' + crypto.createHmac('sha256', secret).update(payload).digest('hex');

if (signature !== expected) {
  throw new Error('HMAC validation failed: invalid signature');
}

// Normalizar estructura al mismo formato que webhook consulta
const msg = $input.first().json.body;
const entry = msg?.entry?.[0]?.changes?.[0]?.value;
const message = entry?.messages?.[0];

return [{
  json: {
    canal: 'whatsapp',
    paciente_tel: message?.from || '',
    texto: message?.text?.body || '',
    tipo_mensaje: message?.type || 'text',
    media_id: message?.audio?.id || message?.image?.id || null,
    timestamp: new Date().toISOString()
  }
}];

const body = $input.first().json.body || $input.first().json;

// Sanitizar inputs - max 1500 chars, remover caracteres peligrosos
const sanitize = (str) => {
  if (!str) return '';
  return str.toString().trim().substring(0, 1500).replace(/<script>/gi, '').replace(/[<>]/g, '');
};

return [{
  json: {
    canal: sanitize(body.canal) || 'web',
    paciente_nombre: sanitize(body.nombre),
    paciente_email: sanitize(body.email),
    paciente_tel: sanitize(body.telefono),
    paciente_dni: sanitize(body.dni),
    texto: sanitize(body.consulta || body.texto || body.message),
    especialidad_solicitada: sanitize(body.especialidad) || 'general',
    tipo_mensaje: 'texto',
    media_id: null,
    timestamp: new Date().toISOString(),
    workflow_id: 'WF1'
  }
}];

const texto = ($json.texto || '').toLowerCase();

// Palabras clave de urgencia con pesos
const urgenciaCritica = [
  'dolor de pecho', 'dolor pecho', 'infarto', 'no puedo respirar',
  'dificultad respirar', 'desmayo', 'perdida conciencia', 'convulsion',
  'sangrado intenso', 'alergia grave', 'anafilaxia', 'suicidio', 'me quiero matar'
];
const urgenciaAlta = [
  'mucho dolor', 'fiebre alta', 'vomito sangre', 'cabeza fuerte',
  'vision doble', 'entumecimiento', 'paralisis', 'accidente'
];
const urgenciaMedia = [
  'dolor', 'fiebre', 'tos', 'mareo', 'nauseas', 'vomito', 'diarrea',
  'erupcion', 'picazon', 'infeccion', 'resultado', 'laboratorio'
];

let score = 20; // base
let nivel = 'bajo';
let urgenciaTipo = 'consulta_general';

if (urgenciaCritica.some(kw => texto.includes(kw))) {
  score = 95; nivel = 'critico'; urgenciaTipo = 'emergencia';
} else if (urgenciaAlta.some(kw => texto.includes(kw))) {
  score = 75; nivel = 'alto'; urgenciaTipo = 'urgencia';
} else if (urgenciaMedia.some(kw => texto.includes(kw))) {
  score = 50; nivel = 'medio'; urgenciaTipo = 'consulta_medica';
}

// Hash PII para logs (anonimizacion HIPAA)
const hashPII = (val) => {
  if (!val) return null;
  let hash = 0;
  for (let i = 0; i < val.length; i++) {
    const char = val.charCodeAt(i);
    hash = ((hash << 5) - hash) + char;
    hash = hash & hash;
  }
  return Math.abs(hash).toString(16).padStart(8, '0');
};

return [{
  json: {
    ...$json,
    urgencia_score: score,
    urgencia_nivel: nivel,
    urgencia_tipo: urgenciaTipo,
    patient_hash: hashPII($json.paciente_dni || $json.paciente_tel),
    procesado_en: new Date().toISOString()
  }
}];
